mapper.insert:
BEGIN

    INSERT INTO SETTLEMENT_DETAILS (
        DETAIL_ID, SETTLEMENT_ID, USER_ID,
        AMOUNT_DUE, PENALTY_AMOUNT, STATUS, UPDATED_AT
    ) VALUES (
        SETTLEMENT_DETAILS_SEQ.NEXTVAL, #{d.settlementId}, #{d.userId},
        #{d.amountDue}, 0, 'WAITING', CURRENT_TIMESTAMP
    );

END;

mapper.update:
UPDATE SETTLEMENTS
SET STATUS = 'COMPLETED'
WHERE SETTLEMENT_ID = #{settlementId}
  AND NOT EXISTS (
      SELECT 1 FROM SETTLEMENT_DETAILS
      WHERE SETTLEMENT_ID = #{settlementId}
        AND STATUS = 'WAITING'
  )

mapper.delete:
DELETE FROM SETTLEMENTS
WHERE SETTLEMENT_ID = #{settlementId}
  AND GROUP_ID      = #{groupId}
